#!/usr/bin/env node
// Generated by OrchestKit Claude Plugin
// Created: 2026-04-19
//
// Scans src/agents/*.md, extracts YAML frontmatter fields that affect
// invocation, and emits a sortable table to stdout. When run with
// --write, stamps src/agents/README.md with a freshly-generated table
// between BEGIN-GENERATED / END-GENERATED markers.
//
// The table answers "which specific ork agent should I spawn for task
// X" — the gap that bit us in Lane 2 when we reached for generic
// general-purpose agents instead of ci-cd-engineer + backend-system-
// architect.
//
// Usage:
//   node scripts/list-invocable-agents.mjs              # table to stdout
//   node scripts/list-invocable-agents.mjs --write       # update README

import { readFile, writeFile, readdir } from 'node:fs/promises';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const PROJECT_ROOT = join(__dirname, '..');
const AGENTS_DIR = join(PROJECT_ROOT, 'src/agents');
const README_PATH = join(PROJECT_ROOT, 'src/agents/README.md');

const BEGIN = '<!-- BEGIN-GENERATED: list-invocable-agents -->';
const END = '<!-- END-GENERATED: list-invocable-agents -->';

// ─── parse YAML frontmatter (minimal, only the fields we need) ─────
function parseFrontmatter(src) {
  const m = src.match(/^---\n([\s\S]*?)\n---/);
  if (!m) return null;
  const out = {};
  for (const line of m[1].split('\n')) {
    const kv = line.match(/^(\w[\w-]*):\s*(.*)$/);
    if (!kv) continue;
    const [, k, vRaw] = kv;
    let v = vRaw.trim();
    // Strip surrounding quotes if any
    if (v.startsWith('"') && v.endsWith('"')) v = v.slice(1, -1);
    if (v.startsWith("'") && v.endsWith("'")) v = v.slice(1, -1);
    out[k] = v;
  }
  return out;
}

// ─── walk agents dir ───────────────────────────────────────────────
async function collectAgents() {
  const entries = await readdir(AGENTS_DIR, { withFileTypes: true });
  const files = entries.filter((e) => e.isFile() && e.name.endsWith('.md'));
  const rows = [];
  for (const f of files) {
    // Skip conventional non-agent docs (README, index, etc.)
    if (/^(README|INDEX|CONTRIBUTING)/i.test(f.name)) continue;
    const src = await readFile(join(AGENTS_DIR, f.name), 'utf8');
    const fm = parseFrontmatter(src);
    if (!fm?.name) continue;
    rows.push({
      name: fm.name,
      category: fm.category || '—',
      model: fm.model || '—',
      effort: fm.effort || '—',
      description: (fm.description || '').replace(/\s+/g, ' ').trim(),
    });
  }
  rows.sort((a, b) =>
    a.category.localeCompare(b.category) || a.name.localeCompare(b.name),
  );
  return rows;
}

// ─── format as markdown table ─────────────────────────────────────
function renderTable(rows) {
  const lines = [];
  lines.push('| Agent | Category | Model | Effort | When to spawn |');
  lines.push('|---|---|---|---|---|');
  for (const r of rows) {
    // Trim description to keep the table readable
    const desc = r.description.length > 110 ? r.description.slice(0, 107) + '…' : r.description;
    lines.push(`| \`${r.name}\` | ${r.category} | ${r.model} | ${r.effort} | ${desc} |`);
  }
  return lines.join('\n');
}

// ─── decision tree block ──────────────────────────────────────────
function decisionTree() {
  return [
    '### Decision tree — which agent for which task',
    '',
    '```',
    'CI / workflow change?         → ci-cd-engineer',
    'Python/backend service?        → backend-system-architect',
    'React/Next.js component?       → frontend-ui-developer',
    'Security audit / OWASP?        → security-auditor',
    'Test generation?               → test-generator',
    'Database schema?               → database-engineer',
    'Infrastructure / IaC?          → infrastructure-architect',
    'LLM / RAG / prompt work?       → llm-integrator',
    'Design to React?               → design-to-code skill  (NOT an agent)',
    'Explore codebase?              → Explore (built-in)',
    'Unsure OR mixed concerns?      → workflow-architect',
    '```',
    '',
  ].join('\n');
}

// ─── main ────────────────────────────────────────────────────────
async function main() {
  const write = process.argv.includes('--write');
  const rows = await collectAgents();
  const table = renderTable(rows);
  const body = [
    '',
    `_Auto-generated by \`scripts/list-invocable-agents.mjs\`. Do not edit between the BEGIN/END markers below; run \`node scripts/list-invocable-agents.mjs --write\` to refresh._`,
    '',
    decisionTree(),
    `### Agent registry (${rows.length} agents)`,
    '',
    table,
    '',
  ].join('\n');

  if (!write) {
    console.log(body);
    return;
  }

  // Update the README between markers (create on first run)
  let existing = '';
  try {
    existing = await readFile(README_PATH, 'utf8');
  } catch {
    // first-time: seed the file
    existing = `# OrchestKit agents\n\nAgents defined under \`src/agents/\` and callable via \`Agent(subagent_type=...)\` when the orchestkit plugin is loaded.\n\n${BEGIN}\n${BEGIN.toUpperCase()}\n${END}\n`;
  }

  const beginIdx = existing.indexOf(BEGIN);
  const endIdx = existing.indexOf(END);
  let updated;
  if (beginIdx === -1 || endIdx === -1) {
    updated = existing.trimEnd() + `\n\n${BEGIN}\n${body.trim()}\n${END}\n`;
  } else {
    const before = existing.slice(0, beginIdx + BEGIN.length);
    const after = existing.slice(endIdx);
    updated = `${before}\n${body.trim()}\n${after}`;
  }

  await writeFile(README_PATH, updated);
  console.log(`Wrote ${rows.length} agents to ${README_PATH}`);
}

main().catch((e) => {
  console.error('list-invocable-agents.mjs failed:', e);
  process.exit(1);
});
